        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val s = edge[2]
        val e = edge[3]
        adj[u].add(arrayOf(v.toDouble(), s, e))
    }

    val dist = LongArray(n.toInt()) { Long.MAX_VALUE }
    dist[0] = 0L

    val pq = PriorityQueue<Pair<Long, Long>>(compareBy { it.first })
    pq.add(Pair(0L, 0L))

    while (pq.isNotEmpty()) {
        val (t, u) = pq.remove()
        if (u == n - 1) return t
        if (t > dist[u.toInt()]) continue

        for (edge in adj[u.toInt()]) {
            val v = edge[0].toLong()
            val s = edge[1]
            val e = edge[2]

            val new_time = Math.max(t, s) + 1
            if (new_time <= e) {
                if (new_time < dist[v.toInt()]) {
                    dist[v.toInt()] = new_time
                    pq.add(Pair(new_time, v))
                }
            }
        }
    }

    return -1L
}
